private struct SoundCloudHomeScreen: View {
    var body: some View {
        ZStack(alignment: .bottom) {
            ScrollView {
                VStack(alignment: .leading, spacing: 20) {
                    Text("Bonsoir").font(.system(size: 28, weight: .bold)).foregroundStyle(SoundCloudTokens.scTextPrimary).padding(.horizontal)
                    LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 12) {
                        ForEach(SoundCloudDemoData.recent) { item in
                            SoundCloudRecentTile(item: item, surface: SoundCloudTokens.scSurface)
                        }
                    }
                    .padding(.horizontal)
                    Text("Récemment joué").font(.system(size: 22, weight: .bold)).foregroundStyle(SoundCloudTokens.scTextPrimary).padding(.horizontal)
                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(spacing: 12) {
                            ForEach(SoundCloudDemoData.playlists) { pl in
                                VStack(alignment: .leading) {
                                    RoundedRectangle(cornerRadius: 6).fill(pl.color).frame(width: 140, height: 140)
                                    Text(pl.title).font(.system(size: 14, weight: .semibold)).foregroundStyle(SoundCloudTokens.scTextPrimary).lineLimit(1)
                                }
                            }
                        }
                        .padding(.horizontal)
                    }
                }
                .padding(.vertical).padding(.bottom, 80)
            }
            .background(SoundCloudTokens.scCanvas.ignoresSafeArea())
            SoundCloudMiniPlayer(accent: SoundCloudTokens.scTextPrimary, surface: SoundCloudTokens.scSurface, textPri: SoundCloudTokens.scTextPrimary)
        }
    }
}

private struct SoundCloudRecentTile: View {
