            Text(item.title).font(.system(size: 14, weight: .semibold)).foregroundStyle(.white).lineLimit(2)
            Spacer(minLength: 0)
        }
        .padding(8).background(RoundedRectangle(cornerRadius: 6).fill(surface))
    }
}

